+    async fn invoke_inner(&self, req: InvokeRequest) -> FcpResult<InvokeResponse> {
+        self.base.check_ready()?;
+        let verifier = self.verifier.as_ref().ok_or(FcpError::NotHandshaken)?;
+        let required_cap = match req.operation.as_str() {
+            OP_HEALTH | OP_GET_STATUS => CapabilityId::from_static(CAP_READ),
+            OP_PLAY | OP_PAUSE | OP_NEXT | OP_PREVIOUS | OP_SET_VOLUME => {
+                CapabilityId::from_static(CAP_WRITE)
+            }
+            operation => {
+                return Err(FcpError::InvalidRequest {
+                    code: 1004,
+                    message: format!("Unknown operation: {operation}"),
+                });
+            }
+        };
+        verifier.verify(&req.capability_token, &required_cap, &req.operation, &[])?;
+        let state = self.state.as_ref().ok_or(FcpError::NotConfigured)?;
+        let output = match req.operation.as_str() {
+            OP_HEALTH => state.client.health().await.map_err(|error| error.to_fcp_error())?,
+            OP_GET_STATUS => state.client.get_status().await.map_err(|error| error.to_fcp_error())?,
+            OP_PLAY => state.client.play().await.map_err(|error| error.to_fcp_error())?,
+            OP_PAUSE => state.client.pause().await.map_err(|error| error.to_fcp_error())?,
+            OP_NEXT => state.client.next().await.map_err(|error| error.to_fcp_error())?,
+            OP_PREVIOUS => state.client.previous().await.map_err(|error| error.to_fcp_error())?,
+            OP_SET_VOLUME => {
+                let volume = req
+                    .input
+                    .get("volume")
+                    .and_then(|value| value.as_u64())
+                    .and_then(|value| u8::try_from(value).ok())
+                    .ok_or(FcpError::InvalidRequest {
+                        code: 1005,
+                        message: "Missing or invalid volume".into(),
+                    })?;
+                if volume > 100 {
+                    return Err(FcpError::InvalidRequest {
+                        code: 1005,
+                        message: "volume must be between 0 and 100".into(),
+                    });
+                }
+                state
+                    .client
+                    .set_volume(volume)
+                    .await
+                    .map_err(|error| error.to_fcp_error())?
+            }
+            _ => unreachable!(),
+        };
+        Ok(InvokeResponse::ok(req.id, output))
+    }
+}
