+        format!("sha256:{}", hex::encode(hasher.finalize()))
+    }
+
+    fn operations() -> Vec<OperationInfo> {
+        vec![
+            operation(
+                OP_SEND_TEXT,
+                "Send a WeCom text message",
+                CAP_MESSAGES_WRITE,
+                RiskLevel::Medium,
+                SafetyTier::Risky,
+                IdempotencyClass::None,
+                json!({
+                    "type": "object",
